UPDATE J09D_temp
SET ENTSCHEIDUNG = (
  SELECT CASE WHEN cnt < 3 THEN 'KSA' ELSE 'EVU' END
  FROM (
    SELECT HAUS, COUNT(DISTINCT EQUNR) AS cnt
    FROM J09D_temp
    GROUP BY HAUS
  ) AS t
  WHERE t.HAUS = J09D_temp.HAUS
);

UPDATE J09D_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 = 0;
